module RefModule(clk, rst_n, resume, halt, en);input clk, rst_n, resume, halt;
    output reg en;
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk, negedge rst_n) begin
        if (!rst_n)
            en = 1'b1;
        else if (resume)
            en = 1'b1;
        else if (halt)
            en = 1'b0;
    end
endmodule
